// Merge webhook wrapper + POST body into ONE item (prevents multi-item loops).
const wrapped = $input.first().json;
const body =
  wrapped.body && typeof wrapped.body === 'object' && !Array.isArray(wrapped.body)
    ? wrapped.body
    : wrapped;

const event = {
  ...wrapped,
  ...body,
  type: body.type ?? wrapped.type ?? 'unknown',
  societyId: body.societyId ?? wrapped.societyId ?? null,
  societyName: body.societyName ?? wrapped.societyName ?? 'Society',
  summary: body.summary ?? wrapped.summary ?? '',
  message_body:
    body.message_body ??
    body.messageBody ??
    body.message ??
    wrapped.message_body ??
    wrapped.message ??
    '',
  sender_whatsapp:
    body.sender_whatsapp ?? body.senderWhatsapp ?? wrapped.sender_whatsapp ?? null,
  receiver_whatsapp:
    body.receiver_whatsapp ??
    body.receiverWhatsapp ??
    body.to ??
    wrapped.receiver_whatsapp ??
    null,
  recipients: Array.isArray(body.recipients)
    ? body.recipients.filter(Boolean)
    : Array.isArray(wrapped.recipients)
      ? wrapped.recipients.filter(Boolean)
      : []
};

function buildWhatsAppMessage(evt) {
  const prebuilt = String(evt.message_body ?? '').trim();
  if (prebuilt) return prebuilt;

  const societyName = evt.societyName ?? 'Society';
  const type = String(evt.type ?? '');

  if (type === 'notice.published') {
    const title = evt.title ?? evt.metadata?.title ?? evt.summary ?? 'New notice';
    const noticeBody = evt.body ?? evt.metadata?.body ?? '';
    return `📢 *${societyName}*\n\n${title}\n\n${noticeBody}\n\n_View in syncra-society portal_`;
  }

  if (type.startsWith('visitor.')) {
    return `🚪 *${societyName}*\n\n${evt.summary ?? 'Visitor update'}\n\n_View in syncra-society portal_`;
  }

  if (type.startsWith('payment.')) {
    return `💳 *${societyName}*\n\n${evt.summary ?? 'Payment update'}\n\n_View in syncra-society portal_`;
  }

  return `*${societyName}*\n\n${evt.summary ?? 'Portal update'}\n\n_View in syncra-society portal_`;
}

const whatsappMessage = buildWhatsAppMessage(event);
const toPhone = event.receiver_whatsapp ?? event.recipients?.[0] ?? null;

return [
  {
    json: {
      ...event,
      whatsappMessage,
      toPhone,
      sendCount: 1
    }
  }
];

// Mock WhatsApp send — single item only (no recipient array fan-out).
const item = $input.first().json;
const message = item.whatsappMessage ?? item.message_body ?? item.summary ?? '';
const toPhone = item.toPhone ?? item.receiver_whatsapp ?? null;

console.log('WhatsApp mock send:', { toPhone, message });

return [
  {
    json: {
      sent: true,
      mock: true,
      toPhone,
      message,
      type: item.type ?? null
    }
  }
];

// Merge inbound Twilio/WhatsApp payload into a single item.
const wrapped = $input.first().json;
const body =
  wrapped.body && typeof wrapped.body === 'object' && !Array.isArray(wrapped.body)
    ? wrapped.body
    : wrapped;

const merged = { ...wrapped, ...body };

return [
  {
    json: {
      societyId: merged.societyId ?? merged.society_id ?? null,
      flatNumber: merged.flatNumber ?? merged.flat_number ?? null,
      phone: merged.phone ?? merged.From ?? merged.from ?? null,
      messageType: merged.messageType ?? merged.message_type ?? 'ticket',
      subject: merged.subject ?? merged.Subject ?? null,
      description:
        merged.description ??
        merged.text ??
        merged.Body ??
        merged.body?.text ??
        null,
      amount: merged.amount ?? null
    }
  }
];
